code = """import json

def clean_id(id_str):
    if not id_str:
        return None
    if id_str.startswith('#'):
        return id_str[1:]
    return id_str

# Load data
users_data = locals()['var_function-call-12451964255223958043']
history_data = locals()['var_function-call-5569577483770029118']
cases_data = locals()['var_function-call-7943005081563767382']

# 1. Valid Users
valid_users = set()
for u in users_data:
    uid = clean_id(u.get('Id'))
    if uid:
        valid_users.add(uid)

# 2. Process History
transfer_counts = {} # UserID -> count
handled_agents = set()

for row in history_data:
    # SQL already filtered by field__c='Owner Assignment', but field__c is not in the result dict.
    # So we assume all rows are Owner Assignment.
    
    old_val = clean_id(row.get('oldvalue__c'))
    new_val = clean_id(row.get('newvalue__c'))
    
    # Check "Handled"
    if old_val in valid_users:
        handled_agents.add(old_val)
    if new_val in valid_users:
        handled_agents.add(new_val)
        
    # Check Transfer Count
    if old_val in valid_users and new_val: # Transfer
        transfer_counts[old_val] = transfer_counts.get(old_val, 0) + 1

# 3. Process Cases (to ensure handled coverage)
for c in cases_data:
    owner = clean_id(c.get('ownerid'))
    if owner in valid_users:
        handled_agents.add(owner)

# 4. Find Min
min_count = float('inf')
candidates = []

# Only consider agents who handled > 0 cases
for agent in handled_agents:
    count = transfer_counts.get(agent, 0)
    if count < min_count:
        min_count = count
        candidates = [agent]
    elif count == min_count:
        candidates.append(agent)

result = {
    "min_transfer_count": min_count,
    "agents": candidates,
    "handled_count": len(handled_agents)
}

print("__RESULT__:")
print(json.dumps(result))"""

